// Custom resource implementing AutoCloseable
class MyResource implements AutoCloseable {
    String name;
    MyResource(String name) {
        this.name = name;
        System.out.println(name + " opened");
    }
    @Override
    public void close() throws Exception {
        System.out.println(name + " closed");
    }
}

// Using with try-with-resources
try (MyResource r = new MyResource("Resource1")) {
    System.out.println("Using " + r.name);
}
// Output:
// Resource1 opened
// Using Resource1
// Resource1 closed

class Res implements AutoCloseable {
    String name;
    Res(String name) {
        this.name = name;
        System.out.println(name + " opened");
    }
    public void close() {
        System.out.println(name + " closed");
    }
}

try (Res r1 = new Res("A"); Res r2 = new Res("B"); Res r3 = new Res("C")) {
    System.out.println("Processing");
}
// Output:
// A opened
// B opened
// C opened
// Processing
// C closed (reverse order)
// B closed
// A closed

// Since Java 9
MyResource r1 = new MyResource("R1");
MyResource r2 = new MyResource("R2");

try (r1; r2) {  // Directly reference variables declared outside
    System.out.println("Using resources");
}
// r1 and r2 are automatically closed

// Note: reassignment causes a compile error
MyResource r3 = new MyResource("R3");
r3 = new MyResource("R3b"); // Reassignment
// try (r3) { } // Compile error! (not effectively final)

