class FailClose implements AutoCloseable {
    public void close() {
        throw new RuntimeException("close error");
    }
}

try (FailClose fc = new FailClose()) {
    throw new RuntimeException("try error");
} catch (RuntimeException e) {
    System.out.println("Primary: " + e.getMessage());
    for (Throwable t : e.getSuppressed()) {
        System.out.println("Suppressed: " + t.getMessage());
    }
}
// Output:
// Primary: try error
// Suppressed: close error

class Res implements AutoCloseable {
    String name;
    Res(String name) { this.name = name; }
    public void close() {
        throw new RuntimeException(name + " close fail");
    }
}

try (Res a = new Res("A"); Res b = new Res("B")) {
    throw new RuntimeException("main error");
} catch (RuntimeException e) {
    System.out.println("Primary: " + e.getMessage());
    for (Throwable t : e.getSuppressed()) {
        System.out.println("Suppressed: " + t.getMessage());
    }
}
// Output:
// Primary: main error
// Suppressed: B close fail (B closes first in reverse order)
// Suppressed: A close fail

RuntimeException primary = new RuntimeException("main");
RuntimeException suppressed1 = new RuntimeException("sub1");
RuntimeException suppressed2 = new RuntimeException("sub2");

primary.addSuppressed(suppressed1);
primary.addSuppressed(suppressed2);

System.out.println(primary.getSuppressed().length); // 2
System.out.println(primary.getSuppressed()[0].getMessage()); // sub1
System.out.println(primary.getSuppressed()[1].getMessage()); // sub2

