public class AssertDemo {
    public static void main(String[] args) {
        int x = 10;
        assert x > 0 : "x should be positive";
        System.out.println("x = " + x);
        // Without -ea → normal output
        // With -ea → AssertionError if x is 0 or less
    }
}

