try {
    // ...
} catch (IOException | SQLException e) {
    // OK: no inheritance relationship
    // e = new IOException(); // Compile error: cannot reassign
    System.out.println(e.getMessage());
}

// Compile error example
try {
    // ...
} catch (FileNotFoundException | IOException e) { // Error!
    // FileNotFoundException is a subclass of IOException
}

// Single catch allows reassignment
try {
    // ...
} catch (IOException e) {
    e = new IOException("wrapped"); // OK
}

// Rethrow type inference since Java 7
public void process() throws IOException, SQLException {
    try {
        // May throw IOException or SQLException
        callMethod();
    } catch (Exception e) {
        // e's type is Exception, but the compiler tracks the actual throw type
        // Only IOException, SQLException need to be declared in throws
        System.out.println("Error: " + e.getMessage());
        throw e; // Compiler treats this as a more specific type
    }
}

// Type inference does not work with reassignment
public void process2() throws Exception { // Exception is required
    try {
        callMethod();
    } catch (Exception e) {
        e = new Exception("changed"); // Reassignment
        throw e; // Can only be inferred as Exception
    }
}

public class ServiceException extends Exception {
    public ServiceException(String msg, Throwable cause) {
        super(msg, cause);
    }
}

public void processData() throws ServiceException {
    try {
        // Database operation
        connectDB();
    } catch (SQLException e) {
        // Wrap SQLException in ServiceException
        throw new ServiceException("Data processing error", e);
    }
}

// Retrieve the cause on the caller side
try {
    processData();
} catch (ServiceException e) {
    System.out.println(e.getMessage()); // Data processing error
    System.out.println(e.getCause());   // java.sql.SQLException: ...
}

